function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    // Helper function to calculate the end time of an activity
    function getActivityEndTime(start: number, duration: number): number {
        return start + duration;
    }

    // Calculate all possible end times for land and water activities
    const landEndTimes: number[] = landStartTime.map((start, i) => getActivityEndTime(start, landDuration[i]));
    const waterEndTimes: number[] = waterStartTime.map((start, j) => getActivityEndTime(start, waterDuration[j]));

    // Try all combinations of one land and one water activity
    let minEndTime = Infinity;

    for (let i = 0; i < landEndTimes.length; i++) {
