            const landStart = Math.max(waterEnd, landStartTime[i]);
            const landEnd2 = getActivityEndTime(landStart, landDuration[i]);
            minEndTime = Math.min(minEndTime, landEnd2);
        }
    }

    return minEndTime;
}

